export default {
  data() {
    return {
      loaded: false,
      items: []
    };
  },
  methods: {
    getStyleProp(item) {
      console.log(item);
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `background-image: url("${host}:${port}/summoner_icons/1.png")`;
    },
    canBuy(item) {
      if (item.price > this.$store.state.user.s4Coins) {
        return true;
      } else {
        return false;
      }
    },
    buyItem(item) {
      this.$store.dispatch("postPurchaseItem", {
        item,
        category: "Boosts"
      }).then(response => {
        if (response.status === 200) {
          this.$sound.template("CORE_SHOP_BUY_GENERAL");
          this.$store.dispatch("getStoreItems", "boosts").then(items => {
            this.items = items;
          });
          this.$store.dispatch("deductUserCoins", item.price);
        }
      });
    }
  },
  beforeMount() {
    this.$store.dispatch("getStoreItems", "boosts").then(items => {
      this.items = items;
      this.loaded = true;
    });
  }
};
